operation.add:
if ($this->config->get('module_xd_gallery_manager_status')==1) {
$gallery = array();
if ($this->user->hasPermission('access', 'extension/module/xd_gallery_manager')) {
    $gallery[] = array(
        'name'     => 'Обзор',
        'href'     => $this->url->link('extension/module/xd_gallery_manager', 'user_token=' . $this->session->data['user_token'], true),
        'children' => array()   
    );
}
if ($this->user->hasPermission('access', 'xd_gallery/album')) {
    $gallery[] = array(
        'name'     => 'Фотоальбомы',
        'href'     => $this->url->link('xd_gallery/album', 'user_token=' . $this->session->data['user_token'], true),
        'children' => array()   
    );
}
if ($this->user->hasPermission('access', 'xd_gallery/video')) {
    $gallery[] = array(
        'name'     => 'Видео',
        'href'     => $this->url->link('xd_gallery/video', 'user_token=' . $this->session->data['user_token'], true),
        'children' => array()   
    );
}
if ($this->user->hasPermission('access', 'xd_gallery/setting')) {
    $gallery[] = array(
        'name'     => 'Настройки',
        'href'     => $this->url->link('xd_gallery/setting', 'user_token=' . $this->session->data['user_token'], true),
        'children' => array()   
    );
}
if ($gallery) {
    $data['menus'][] = array(
        'id'       => 'menu-gallery',
        'icon'     => 'fa-image', 
        'name'     => 'Галерея',
        'href'     => '',
        'children' => $gallery
    );      
}
}


if ($this->config->get('og_album_menu')) {
    $data['categories'][] = array(
        'name'     => $this->config->get('og_album_title'),
        'children' => '',
        'column'   => 1,
        'href'     => $this->url->link('gallery/album', '', true)
    );
}
if ($this->config->get('og_video_menu')) {
    $data['categories'][] = array(
        'name'     => $this->config->get('og_video_title'),
        'children' => '',
        'column'   => 1,
        'href'     => $this->url->link('gallery/video', '', true)
    );
}

if ($this->config->get('og_sitemap')){
    $output .= '<url>';
    $output .= '<loc>' . $this->url->link('gallery/album', '', true) . '</loc>';
    $output .= '<changefreq>weekly</changefreq>';
    $output .= '<priority>0.7</priority>';
    $output .= '</url>';
    $this->load->model('gallery/album');
    $albums = $this->model_gallery_album->getAlbums(array());
    if ($albums){
        foreach ($albums as $album) {
            $output .= '<url>';
            $output .= '<loc>' . $this->url->link('gallery/album', 'album_id=' . $album['album_id'], true) . '</loc>';
            $output .= '<changefreq>weekly</changefreq>';
            $output .= '<priority>0.5</priority>';
            $output .= '</url>';
        }
    }
    $output .= '<url>';
    $output .= '<loc>' . $this->url->link('gallery/video', '', true) . '</loc>';
    $output .= '<changefreq>weekly</changefreq>';
    $output .= '<priority>0.7</priority>';
    $output .= '</url>';
    $this->load->model('gallery/video');
    $videos = $this->model_gallery_video->getVideos(array());
    if ($videos){
        foreach ($videos as $video) {
            $output .= '<url>';
            $output .= '<loc>' . $this->url->link('gallery/video', 'video_id=' . $video['video_id'], true) . '</loc>';
            $output .= '<changefreq>weekly</changefreq>';
            $output .= '<priority>0.5</priority>';
            $output .= '</url>';
        }
    }
}

            if ($this->config->get('og_sitemap')){
                $this->load->model('gallery/album');
                $data['albums'] = array();
                $data['albums'][] = array(
                    'name'      => 'Фотогалерея',
                    'href'       => $this->url->link('gallery/album', '' , true)
                );
                $albums = $this->model_gallery_album->getAlbums(array());
                if ($albums){
                    foreach ($albums as $album) {
                        $data['albums'][] = array(
                            'name'      => $album['name'],
                            'href'       => $this->url->link('gallery/album', 'album_id=' . $album['album_id'], true)
                        );
                    }
                }

                $this->load->model('gallery/video');
                $data['videos'] = array();
                $data['videos'][] = array(
                    'name'      => 'Видеогалерея',
                    'href'       => $this->url->link('gallery/video', '' , true)
                );
                $videos = $this->model_gallery_video->getVideos(array());
                if ($videos){
                    foreach ($videos as $video) {
                        $data['videos'][] = array(
                            'name'      => $video['name'],
                            'href'       => $this->url->link('gallery/video', 'video_id=' . $video['video_id'], true)
                        );
                    }
                }
            }
